### 2. JavaScript Interop (wwwroot/js/indexeddb.js)

Create `wwwroot/js/indexeddb.js`:
```javascript
const DB_NAME = 'SiteInspectorDB';
const DB_VERSION = 1;

let db = null;

function openDb() {
    return new Promise((resolve, reject) => {
        if (db) { resolve(db); return; }
        const request = indexedDB.open(DB_NAME, DB_VERSION);
        request.onupgradeneeded = (e) => {
            const database = e.target.result;
            if (!database.objectStoreNames.contains('sites')) {
                database.createObjectStore('sites', { keyPath: 'id' });
            }
            if (!database.objectStoreNames.contains('inspections')) {
                const store = database.createObjectStore('inspections', { keyPath: 'id' });
                store.createIndex('siteId', 'siteId', { unique: false });
                store.createIndex('isSynced', 'isSynced', { unique: false });
            }
            if (!database.objectStoreNames.contains('photos')) {
                const store = database.createObjectStore('photos', { keyPath: 'id' });
                store.createIndex('inspectionId', 'inspectionId', { unique: false });
            }
        };
        request.onsuccess = (e) => { db = e.target.result; resolve(db); };
        request.onerror = (e) => reject(e.target.error);
    });
}

window.indexedDbInterop = {
    initialize: async function() {
        await openDb();
        return true;
    },

    putItem: async function(storeName, item) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readwrite');
            tx.objectStore(storeName).put(JSON.parse(item));
            tx.oncomplete = () => resolve(true);
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    getItem: async function(storeName, id) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const request = tx.objectStore(storeName).get(id);
            request.onsuccess = () => resolve(request.result ? JSON.stringify(request.result) : null);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getAllItems: async function(storeName) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const request = tx.objectStore(storeName).getAll();
            request.onsuccess = () => resolve(JSON.stringify(request.result || []));
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getItemsByIndex: async function(storeName, indexName, key) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const index = tx.objectStore(storeName).index(indexName);
            const request = index.getAll(key);
            request.onsuccess = () => resolve(JSON.stringify(request.result || []));
            request.onerror = (e) => reject(e.target.error);
        });
    },

    deleteItem: async function(storeName, id) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readwrite');
            tx.objectStore(storeName).delete(id);
            tx.oncomplete = () => resolve(true);
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    getUnsyncedCount: async function() {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction('inspections', 'readonly');
            const index = tx.objectStore('inspections').index('isSynced');
            const request = index.count(false);
            request.onsuccess = () => resolve(request.result);
            request.onerror = (e) => reject(e.target.error);
        });
    }
};

window.connectivityInterop = {
    isOnline: function() {
        return navigator.onLine;
    },
    registerOnlineHandler: function(dotnetHelper) {
        window.addEventListener('online', () => {
            dotnetHelper.invokeMethodAsync('OnConnectivityChanged', true);
        });
        window.addEventListener('offline', () => {
            dotnetHelper.invokeMethodAsync('OnConnectivityChanged', false);
        });
    }
};

window.cameraInterop = {
    capturePhoto: function(inputId) {
        return new Promise((resolve) => {
            const input = document.getElementById(inputId);
            if (!input) { resolve(null); return; }

            input.onchange = (e) => {
                const file = e.target.files[0];
                if (!file) { resolve(null); return; }

                const reader = new FileReader();
                reader.onload = (ev) => {
                    const base64 = ev.target.result.split(',')[1];
                    resolve(JSON.stringify({
                        fileName: file.name,
                        contentType: file.type || 'image/jpeg',
                        base64Data: base64
                    }));
                };
                reader.readAsDataURL(file);
            };
            input.click();
        });
    }
};
```

### 3. Services (create Services/ folder)

**Services/IndexedDbService.cs**:
```csharp
using Microsoft.JSInterop;
using System.Text.Json;
using SiteInspector.Models;

namespace SiteInspector.Services;

public class IndexedDbService
{
    private readonly IJSRuntime _js;
    private static readonly JsonSerializerOptions JsonOptions = new()
    {
        PropertyNamingPolicy = JsonNamingPolicy.CamelCase,
        PropertyNameCaseInsensitive = true
    };

    public IndexedDbService(IJSRuntime js)
    {
        _js = js;
    }

    public async Task InitializeAsync()
    {
        await _js.InvokeVoidAsync("indexedDbInterop.initialize");
    }

    // Sites
    public async Task SaveSiteAsync(Site site)
    {
        var json = JsonSerializer.Serialize(site, JsonOptions);
        await _js.InvokeVoidAsync("indexedDbInterop.putItem", "sites", json);
    }

    public async Task<List<Site>> GetAllSitesAsync()
    {
        var json = await _js.InvokeAsync<string>("indexedDbInterop.getAllItems", "sites");
        return JsonSerializer.Deserialize<List<Site>>(json, JsonOptions) ?? new();
    }

    public async Task<Site?> GetSiteAsync(string id)
    {
        var json = await _js.InvokeAsync<string?>("indexedDbInterop.getItem", "sites", id);
        return json is null ? null : JsonSerializer.Deserialize<Site>(json, JsonOptions);
    }

    public async Task DeleteSiteAsync(string id)
    {
        await _js.InvokeVoidAsync("indexedDbInterop.deleteItem", "sites", id);
    }

    // Inspections
    public async Task SaveInspectionAsync(Inspection inspection)
    {
        inspection.LastModified = DateTime.UtcNow;
        var json = JsonSerializer.Serialize(inspection, JsonOptions);
        await _js.InvokeVoidAsync("indexedDbInterop.putItem", "inspections", json);
    }

    public async Task<List<Inspection>> GetAllInspectionsAsync()
    {
        var json = await _js.InvokeAsync<string>("indexedDbInterop.getAllItems", "inspections");
        return JsonSerializer.Deserialize<List<Inspection>>(json, JsonOptions) ?? new();
    }

    public async Task<Inspection?> GetInspectionAsync(string id)
    {
        var json = await _js.InvokeAsync<string?>("indexedDbInterop.getItem", "inspections", id);
        return json is null ? null : JsonSerializer.Deserialize<Inspection>(json, JsonOptions);
    }

    public async Task<List<Inspection>> GetInspectionsBySiteAsync(string siteId)
    {
        var json = await _js.InvokeAsync<string>("indexedDbInterop.getItemsByIndex", "inspections", "siteId", siteId);
        return JsonSerializer.Deserialize<List<Inspection>>(json, JsonOptions) ?? new();
    }

    public async Task DeleteInspectionAsync(string id)
    {
        await _js.InvokeVoidAsync("indexedDbInterop.deleteItem", "inspections", id);
    }

    // Photos
    public async Task SavePhotoAsync(InspectionPhoto photo)
    {
        var json = JsonSerializer.Serialize(photo, JsonOptions);
        await _js.InvokeVoidAsync("indexedDbInterop.putItem", "photos", json);
    }

    public async Task<List<InspectionPhoto>> GetPhotosByInspectionAsync(string inspectionId)
    {
        var json = await _js.InvokeAsync<string>("indexedDbInterop.getItemsByIndex", "photos", "inspectionId", inspectionId);
        return JsonSerializer.Deserialize<List<InspectionPhoto>>(json, JsonOptions) ?? new();
    }

    public async Task<InspectionPhoto?> GetPhotoAsync(string id)
    {
        var json = await _js.InvokeAsync<string?>("indexedDbInterop.getItem", "photos", id);
        return json is null ? null : JsonSerializer.Deserialize<InspectionPhoto>(json, JsonOptions);
    }

    public async Task DeletePhotoAsync(string id)
    {
        await _js.InvokeVoidAsync("indexedDbInterop.deleteItem", "photos", id);
    }

    // Sync
    public async Task<int> GetUnsyncedCountAsync()
    {
        return await _js.InvokeAsync<int>("indexedDbInterop.getUnsyncedCount");
    }
}
```

**Services/ConnectivityService.cs**:
```csharp
using Microsoft.JSInterop;

namespace SiteInspector.Services;

public class ConnectivityService : IAsyncDisposable
{
    private readonly IJSRuntime _js;
    private DotNetObjectReference<ConnectivityService>? _dotNetRef;

    public bool IsOnline { get; private set; }
    public event Action<bool>? ConnectivityChanged;

    public ConnectivityService(IJSRuntime js)
    {
        _js = js;
    }

    public async Task InitializeAsync()
    {
        _dotNetRef = DotNetObjectReference.Create(this);
        IsOnline = await _js.InvokeAsync<bool>("connectivityInterop.isOnline");
        await _js.InvokeVoidAsync("connectivityInterop.registerOnlineHandler", _dotNetRef);
    }

    [JSInvokable]
    public Task OnConnectivityChanged(bool isOnline)
    {
        IsOnline = isOnline;
        ConnectivityChanged?.Invoke(isOnline);
        return Task.CompletedTask;
    }

    public async ValueTask DisposeAsync()
    {
        _dotNetRef?.Dispose();
        await ValueTask.CompletedTask;
    }
}
```

**Services/SyncService.cs**:
```csharp
using System.Net.Http.Json;
using SiteInspector.Models;

namespace SiteInspector.Services;

public class SyncService
{
    private readonly IndexedDbService _db;
    private readonly ConnectivityService _connectivity;
    private readonly HttpClient _http;
    private bool _isSyncing;

    public event Action<string>? SyncStatusChanged;
    public int PendingCount { get; private set; }

    public SyncService(IndexedDbService db, ConnectivityService connectivity, HttpClient http)
    {
        _db = db;
        _connectivity = connectivity;
        _http = http;
        _connectivity.ConnectivityChanged += OnConnectivityChanged;
    }

    private async void OnConnectivityChanged(bool isOnline)
    {
        if (isOnline)
        {
            await SyncAsync();
        }
    }

    public async Task SyncAsync()
    {
        if (_isSyncing || !_connectivity.IsOnline) return;

        _isSyncing = true;
        SyncStatusChanged?.Invoke("Syncing...");

        try
        {
            var inspections = await _db.GetAllInspectionsAsync();
            var unsynced = inspections.Where(i => !i.IsSynced).ToList();

            foreach (var inspection in unsynced)
            {
                try
                {
                    // In a real app, this would POST to an API
                    // For now, we mark as synced after a simulated delay
                    // await _http.PostAsJsonAsync("api/inspections", inspection);

                    inspection.IsSynced = true;
                    await _db.SaveInspectionAsync(inspection);
                }
                catch (HttpRequestException)
                {
                    // Server unreachable, will retry later
                    break;
                }
            }

            PendingCount = await _db.GetUnsyncedCountAsync();
            SyncStatusChanged?.Invoke(PendingCount > 0 ? $"{PendingCount} pending" : "All synced");
        }
        catch (Exception ex)
        {
            SyncStatusChanged?.Invoke($"Sync error: {ex.Message}");
        }
        finally
        {
            _isSyncing = false;
        }
    }

    public async Task UpdatePendingCountAsync()
    {
        PendingCount = await _db.GetUnsyncedCountAsync();
    }
}
```

