        <p>Tap + to add your first site.</p>
    </div>
}
else
{
    <div class="site-list">
        @foreach (var site in sites.OrderByDescending(s => s.CreatedAt))
        {
            <div class="site-card" @onclick="() => ViewSite(site.Id)">
                <div class="site-name">@site.Name</div>
                <div class="site-address">@site.Address</div>
            </div>
        }
    </div>
}

@if (showAddForm)
{
