            </div>
            <div class="form-group">
                <label>Address</label>
                <input type="text" @bind="newSiteAddress" placeholder="e.g., 123 Oak St" class="form-input" />
            </div>
            <div class="modal-actions">
                <button class="btn-cancel" @onclick="() => showAddForm = false">Cancel</button>
                <button class="btn-primary" @onclick="AddSite">Add Site</button>
            </div>
        </div>
    </div>
}

<button class="fab" @onclick="() => showAddForm = true">+</button>

@code {
    private List<Site>? sites;
    private bool showAddForm;
    private string newSiteName = "";
    private string newSiteAddress = "";
    private bool isOnline;

    [CascadingParameter]
    public bool IsOnline { get; set; }

    protected override async Task OnInitializedAsync()
    {
        await Db.InitializeAsync();
        sites = await Db.GetAllSitesAsync();
    }

    protected override void OnParametersSet()
    {
        isOnline = IsOnline;
    }

    private async Task AddSite()
    {
        if (string.IsNullOrWhiteSpace(newSiteName)) return;

        var site = new Site
        {
            Name = newSiteName.Trim(),
            Address = newSiteAddress.Trim()
        };

        await Db.SaveSiteAsync(site);
        sites = await Db.GetAllSitesAsync();
        newSiteName = "";
        newSiteAddress = "";
        showAddForm = false;
    }

    private void ViewSite(string siteId)
    {
        Nav.NavigateTo($"/site/{siteId}");
    }
}
