        </div>
    </div>

    <!-- Tab navigation -->
    <div class="tab-bar">
        <button class="tab @(activeTab == "checklist" ? "active" : "")" @onclick='() => activeTab = "checklist"'>
            Checklist
        </button>
        <button class="tab @(activeTab == "photos" ? "active" : "")" @onclick='() => activeTab = "photos"'>
            Photos (@photos.Count)
        </button>
        <button class="tab @(activeTab == "notes" ? "active" : "")" @onclick='() => activeTab = "notes"'>
            Notes
        </button>
    </div>

    @if (activeTab == "checklist")
    {
        <div class="checklist">
            @foreach (var category in inspection.ChecklistItems.GroupBy(c => c.Category))
            {
                <div class="checklist-category">
                    <h3>@category.Key</h3>
                    @foreach (var item in category)
                    {
                        <div class="checklist-item @GetItemClass(item)">
                            <div class="checklist-item-main" @onclick="() => CycleResult(item)">
                                <span class="result-icon">@GetResultIcon(item.Result)</span>
                                <span class="item-description">@item.Description</span>
                            </div>
                            <button class="btn-note-toggle" @onclick="() => ToggleItemNote(item.Id)">
                                @(string.IsNullOrEmpty(item.Notes) ? "📝" : "📝✓")
                            </button>
                            @if (expandedItemId == item.Id)
                            {
                                <div class="item-notes">
                                    <textarea @bind="item.Notes" @bind:event="oninput" 
                                              placeholder="Add note..." class="form-input note-input"
                                              @onfocusout="() => SaveInspection()"></textarea>
                                </div>
                            }
                        </div>
                    }
                </div>
            }
        </div>
    }
    else if (activeTab == "photos")
    {
        <div class="photos-section">
            <input type="file" id="photoInput" accept="image/*" capture="environment" style="display:none" @onchange="OnPhotoSelected" />
            <button class="btn-primary btn-large" @onclick="CapturePhoto">📷 Take Photo</button>

            @if (photos.Count > 0)
            {
                <div class="photo-grid">
