            @Body
        </CascadingValue>
    </main>

    <div class="connectivity-bar @(isOnline ? "online" : "offline")">
        @if (!isOnline)
        {
            <span>📡 Offline — changes saved locally</span>
        }
        else if (Sync.PendingCount > 0)
        {
            <span>⏳ @Sync.PendingCount inspection(s) pending sync</span>
        }
    </div>
</div>

@code {
    private bool isOnline;

    protected override async Task OnInitializedAsync()
    {
        await Connectivity.InitializeAsync();
        isOnline = Connectivity.IsOnline;
        Connectivity.ConnectivityChanged += OnConnectivityChanged;
        Sync.SyncStatusChanged += OnSyncStatusChanged;
        await Sync.UpdatePendingCountAsync();
    }

    private void OnConnectivityChanged(bool online)
    {
        isOnline = online;
        InvokeAsync(StateHasChanged);
    }

    private void OnSyncStatusChanged(string status)
    {
        InvokeAsync(StateHasChanged);
    }
}
