**Pages/InspectionDetail.razor** — Full inspection with checklist and photos:
```razor
@page "/inspection/{InspectionId}"
@using SiteInspector.Models
@using SiteInspector.Services
@inject IndexedDbService Db
@inject NavigationManager Nav
@inject IJSRuntime JS

<PageTitle>Inspection</PageTitle>

@if (inspection is null)
{
    <div class="loading">Loading inspection...</div>
}
else
{
    <div class="page-header">
        <button class="btn-back" @onclick='() => Nav.NavigateTo($"/site/{inspection.SiteId}")'>← Back</button>
        <h1>Inspection</h1>
    </div>

    <div class="inspection-summary">
        <div class="summary-row">
            <span>Site:</span> <strong>@inspection.SiteName</strong>
        </div>
        <div class="summary-row">
            <span>Date:</span> <strong>@inspection.InspectionDate.ToString("MMM dd, yyyy h:mm tt")</strong>
        </div>
        <div class="summary-row">
            <span>Inspector:</span> <strong>@(string.IsNullOrEmpty(inspection.Inspector) ? "—" : inspection.Inspector)</strong>
        </div>
        <div class="summary-row">
            <span>Progress:</span> <strong>@checkedCount / @inspection.ChecklistItems.Count items</strong>
        </div>
    </div>

    <!-- Tab navigation -->
    <div class="tab-bar">
        <button class="tab @(activeTab == "checklist" ? "active" : "")" @onclick='() => activeTab = "checklist"'>
            Checklist
        </button>
        <button class="tab @(activeTab == "photos" ? "active" : "")" @onclick='() => activeTab = "photos"'>
            Photos (@photos.Count)
        </button>
        <button class="tab @(activeTab == "notes" ? "active" : "")" @onclick='() => activeTab = "notes"'>
            Notes
        </button>
    </div>

    @if (activeTab == "checklist")
    {
        <div class="checklist">
            @foreach (var category in inspection.ChecklistItems.GroupBy(c => c.Category))
            {
                <div class="checklist-category">
                    <h3>@category.Key</h3>
                    @foreach (var item in category)
                    {
                        <div class="checklist-item @GetItemClass(item)">
                            <div class="checklist-item-main" @onclick="() => CycleResult(item)">
                                <span class="result-icon">@GetResultIcon(item.Result)</span>
                                <span class="item-description">@item.Description</span>
                            </div>
                            <button class="btn-note-toggle" @onclick="() => ToggleItemNote(item.Id)">
                                @(string.IsNullOrEmpty(item.Notes) ? "📝" : "📝✓")
                            </button>
                            @if (expandedItemId == item.Id)
                            {
                                <div class="item-notes">
                                    <textarea @bind="item.Notes" @bind:event="oninput" 
                                              placeholder="Add note..." class="form-input note-input"
                                              @onfocusout="() => SaveInspection()"></textarea>
                                </div>
                            }
                        </div>
                    }
                </div>
            }
        </div>
    }
    else if (activeTab == "photos")
    {
        <div class="photos-section">
            <input type="file" id="photoInput" accept="image/*" capture="environment" style="display:none" @onchange="OnPhotoSelected" />
            <button class="btn-primary btn-large" @onclick="CapturePhoto">📷 Take Photo</button>

            @if (photos.Count > 0)
            {
                <div class="photo-grid">
                    @foreach (var photo in photos.OrderByDescending(p => p.CapturedAt))
                    {
                        <div class="photo-card">
                            <img src="data:@photo.ContentType;base64,@photo.Base64Data" alt="@photo.Caption" />
                            <div class="photo-caption-area">
                                <input type="text" @bind="photo.Caption" @bind:event="oninput" 
                                       placeholder="Add caption..." class="caption-input"
                                       @onfocusout="() => SavePhoto(photo)" />
                            </div>
                            <button class="btn-delete-photo" @onclick="() => DeletePhoto(photo)">✕</button>
                        </div>
                    }
                </div>
            }
            else
            {
                <div class="empty-state">
                    <p>No photos yet. Tap the button to capture.</p>
                </div>
            }
        </div>
    }
    else if (activeTab == "notes")
    {
        <div class="notes-section">
            <div class="form-group">
                <label>General Notes</label>
                <textarea @bind="inspection.Notes" @bind:event="oninput" 
                          placeholder="Overall observations, concerns, follow-up items..."
                          class="form-input" rows="6"
                          @onfocusout="SaveInspection"></textarea>
            </div>
        </div>
    }

    <!-- Status and complete actions -->
    <div class="inspection-actions">
        <select @bind="inspection.Status" @bind:after="SaveInspection" class="form-input status-select">
            <option value="@InspectionStatus.InProgress">In Progress</option>
            <option value="@InspectionStatus.Completed">Completed</option>
            <option value="@InspectionStatus.RequiresFollowUp">Requires Follow-Up</option>
        </select>
    </div>
}

@code {
    [Parameter] public string InspectionId { get; set; } = "";

    private Inspection? inspection;
    private List<InspectionPhoto> photos = new();
    private string activeTab = "checklist";
    private string? expandedItemId;
    private int checkedCount => inspection?.ChecklistItems.Count(i => i.Result != CheckResult.NotInspected) ?? 0;

    protected override async Task OnInitializedAsync()
    {
        await Db.InitializeAsync();
        inspection = await Db.GetInspectionAsync(InspectionId);
        if (inspection is not null)
        {
            photos = await Db.GetPhotosByInspectionAsync(InspectionId);
        }
    }

    private async void CycleResult(ChecklistItem item)
    {
        item.Result = item.Result switch
        {
            CheckResult.NotInspected => CheckResult.Pass,
            CheckResult.Pass => CheckResult.Fail,
            CheckResult.Fail => CheckResult.NotApplicable,
            CheckResult.NotApplicable => CheckResult.NotInspected,
            _ => CheckResult.NotInspected
        };
        StateHasChanged();
        await SaveInspection();
    }

    private void ToggleItemNote(string itemId)
    {
        expandedItemId = expandedItemId == itemId ? null : itemId;
    }

    private string GetResultIcon(CheckResult result) => result switch
    {
        CheckResult.Pass => "✅",
        CheckResult.Fail => "❌",
        CheckResult.NotApplicable => "➖",
        _ => "⬜"
    };

    private string GetItemClass(ChecklistItem item) => item.Result switch
    {
        CheckResult.Pass => "item-pass",
        CheckResult.Fail => "item-fail",
        CheckResult.NotApplicable => "item-na",
        _ => ""
    };

    private async Task SaveInspection()
    {
        if (inspection is null) return;
        await Db.SaveInspectionAsync(inspection);
    }

    private async Task CapturePhoto()
    {
        var result = await JS.InvokeAsync<string?>("cameraInterop.capturePhoto", "photoInput");
        if (result is null) return;

        var photoData = System.Text.Json.JsonSerializer.Deserialize<PhotoCaptureResult>(result);
        if (photoData is null) return;

        var photo = new InspectionPhoto
        {
            InspectionId = InspectionId,
            FileName = photoData.FileName ?? "photo.jpg",
            ContentType = photoData.ContentType ?? "image/jpeg",
            Base64Data = photoData.Base64Data ?? ""
        };

        await Db.SavePhotoAsync(photo);
        photos.Add(photo);

        if (inspection is not null)
        {
            inspection.PhotoIds.Add(photo.Id);
            await SaveInspection();
        }
    }

    private async Task OnPhotoSelected()
    {
        // Handled by JS interop in CapturePhoto
    }

    private async Task SavePhoto(InspectionPhoto photo)
    {
        await Db.SavePhotoAsync(photo);
    }

    private async Task DeletePhoto(InspectionPhoto photo)
    {
        await Db.DeletePhotoAsync(photo.Id);
        photos.Remove(photo);
        if (inspection is not null)
        {
            inspection.PhotoIds.Remove(photo.Id);
            await SaveInspection();
        }
    }

    private record PhotoCaptureResult(string? FileName, string? ContentType, string? Base64Data);
}
