@code {
    [Parameter] public string InspectionId { get; set; } = "";

    private Inspection? inspection;
    private List<InspectionPhoto> photos = new();
    private string activeTab = "checklist";
    private string? expandedItemId;
    private int checkedCount => inspection?.ChecklistItems.Count(i => i.Result != CheckResult.NotInspected) ?? 0;

    protected override async Task OnInitializedAsync()
    {
        await Db.InitializeAsync();
        inspection = await Db.GetInspectionAsync(InspectionId);
        if (inspection is not null)
        {
            photos = await Db.GetPhotosByInspectionAsync(InspectionId);
        }
    }

    private async void CycleResult(ChecklistItem item)
    {
        item.Result = item.Result switch
        {
            CheckResult.NotInspected => CheckResult.Pass,
            CheckResult.Pass => CheckResult.Fail,
            CheckResult.Fail => CheckResult.NotApplicable,
            CheckResult.NotApplicable => CheckResult.NotInspected,
            _ => CheckResult.NotInspected
        };
        StateHasChanged();
        await SaveInspection();
    }

    private void ToggleItemNote(string itemId)
    {
        expandedItemId = expandedItemId == itemId ? null : itemId;
    }

    private string GetResultIcon(CheckResult result) => result switch
    {
        CheckResult.Pass => "✅",
        CheckResult.Fail => "❌",
        CheckResult.NotApplicable => "➖",
        _ => "⬜"
    };

    private string GetItemClass(ChecklistItem item) => item.Result switch
    {
        CheckResult.Pass => "item-pass",
        CheckResult.Fail => "item-fail",
        CheckResult.NotApplicable => "item-na",
        _ => ""
    };

    private async Task SaveInspection()
    {
        if (inspection is null) return;
        await Db.SaveInspectionAsync(inspection);
    }

    private async Task CapturePhoto()
    {
        var result = await JS.InvokeAsync<string?>("cameraInterop.capturePhoto", "photoInput");
        if (result is null) return;

        var photoData = System.Text.Json.JsonSerializer.Deserialize<PhotoCaptureResult>(result);
        if (photoData is null) return;

        var photo = new InspectionPhoto
        {
            InspectionId = InspectionId,
            FileName = photoData.FileName ?? "photo.jpg",
            ContentType = photoData.ContentType ?? "image/jpeg",
            Base64Data = photoData.Base64Data ?? ""
        };

        await Db.SavePhotoAsync(photo);
        photos.Add(photo);

        if (inspection is not null)
        {
            inspection.PhotoIds.Add(photo.Id);
            await SaveInspection();
        }
    }

    private async Task OnPhotoSelected()
    {
        // Handled by JS interop in CapturePhoto
    }

    private async Task SavePhoto(InspectionPhoto photo)
    {
        await Db.SavePhotoAsync(photo);
    }

    private async Task DeletePhoto(InspectionPhoto photo)
    {
        await Db.DeletePhotoAsync(photo.Id);
        photos.Remove(photo);
        if (inspection is not null)
        {
            inspection.PhotoIds.Remove(photo.Id);
            await SaveInspection();
        }
    }

    private record PhotoCaptureResult(string? FileName, string? ContentType, string? Base64Data);
}
