@page "/"
@using SiteInspector.Models
@using SiteInspector.Services
@inject IndexedDbService Db
@inject NavigationManager Nav

<PageTitle>Site Inspector</PageTitle>

<div class="page-header">
    <h1>Construction Sites</h1>
    <div class="sync-badge @(IsOnline ? "online" : "offline")">
        @(IsOnline ? "● Online" : "● Offline")
    </div>
</div>

@if (sites is null)
{
    <div class="loading">Loading sites...</div>
}
else if (sites.Count == 0)
{
    <div class="empty-state">
        <div class="empty-icon">🏗️</div>
        <p>No construction sites yet.</p>
        <p>Tap + to add your first site.</p>
    </div>
