arguments.new_str:
:root {
    --primary: #1a73e8;
    --primary-dark: #1557b0;
    --success: #34a853;
    --danger: #ea4335;
    --warning: #fbbc04;
    --bg: #f8f9fa;
    --surface: #ffffff;
    --text: #202124;
    --text-secondary: #5f6368;
    --border: #e0e0e0;
    --radius: 12px;
    --shadow: 0 2px 8px rgba(0,0,0,0.1);
}

* {
    box-sizing: border-box;
    -webkit-tap-highlight-color: transparent;
}

html, body {
    margin: 0;
    padding: 0;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    background: var(--bg);
    color: var(--text);
    font-size: 16px;
    line-height: 1.5;
    overscroll-behavior: none;
    -webkit-overflow-scrolling: touch;
}

.app-container {
    min-height: 100dvh;
    display: flex;
    flex-direction: column;
}

.main-content {
    flex: 1;
    padding: 16px;
    padding-bottom: 80px;
    max-width: 768px;
    margin: 0 auto;
    width: 100%;
}

/* Page Header */
.page-header {
    display: flex;
    align-items: center;
    gap: 12px;
    margin-bottom: 20px;
    flex-wrap: wrap;
}

.page-header h1 {
    font-size: 1.5rem;
    margin: 0;
    flex: 1;
}

/* Buttons */
.btn-back {
    background: none;
    border: none;
    font-size: 1rem;
    color: var(--primary);
    cursor: pointer;
    padding: 8px 4px;
    font-weight: 500;
}

.btn-primary {
    background: var(--primary);
    color: white;
    border: none;
    border-radius: var(--radius);
    padding: 12px 24px;
    font-size: 1rem;
    font-weight: 500;
    cursor: pointer;
    touch-action: manipulation;
}

.btn-primary:active {
    background: var(--primary-dark);
    transform: scale(0.97);
}

.btn-large {
    width: 100%;
    padding: 16px;
    font-size: 1.1rem;
}

.btn-cancel {
    background: none;
    border: 1px solid var(--border);
    border-radius: var(--radius);
    padding: 12px 24px;
    font-size: 1rem;
    cursor: pointer;
}

/* FAB */
.fab {
    position: fixed;
    bottom: 80px;
    right: 20px;
    width: 60px;
    height: 60px;
    border-radius: 50%;
    background: var(--primary);
    color: white;
    border: none;
    font-size: 2rem;
    display: flex;
    align-items: center;
    justify-content: center;
    box-shadow: 0 4px 12px rgba(26, 115, 232, 0.4);
    cursor: pointer;
    touch-action: manipulation;
    z-index: 100;
}

.fab:active {
    transform: scale(0.9);
}

/* Cards */
.site-card, .inspection-card {
    background: var(--surface);
    border-radius: var(--radius);
    padding: 16px;
    margin-bottom: 12px;
    box-shadow: var(--shadow);
    cursor: pointer;
    touch-action: manipulation;
    transition: transform 0.1s;
}

.site-card:active, .inspection-card:active {
    transform: scale(0.98);
}

.site-name {
    font-size: 1.1rem;
    font-weight: 600;
}

.site-address, .site-address-detail {
    color: var(--text-secondary);
    margin-top: 4px;
}

.inspection-date {
    font-weight: 600;
}

.inspection-meta {
    display: flex;
    gap: 12px;
    margin-top: 6px;
    align-items: center;
}

.inspection-inspector {
    color: var(--text-secondary);
    margin-top: 4px;
    font-size: 0.9rem;
}

/* Status badges */
.status-badge {
    font-size: 0.8rem;
    padding: 2px 8px;
    border-radius: 12px;
    font-weight: 500;
}

.status-badge.inprogress { background: #e8f0fe; color: var(--primary); }
.status-badge.completed { background: #e6f4ea; color: var(--success); }
.status-badge.requiresfollowup { background: #fef7e0; color: #e37400; }

.sync-indicator {
    font-size: 0.8rem;
    color: var(--text-secondary);
}

/* Forms */
.form-group {
    margin-bottom: 16px;
}

.form-group label {
    display: block;
    font-weight: 500;
    margin-bottom: 6px;
    font-size: 0.9rem;
}

.form-input {
    width: 100%;
    padding: 14px;
    border: 1px solid var(--border);
    border-radius: var(--radius);
    font-size: 1rem;
    font-family: inherit;
    outline: none;
    transition: border-color 0.2s;
}

.form-input:focus {
    border-color: var(--primary);
}

/* Modal */
.modal-overlay {
    position: fixed;
    inset: 0;
    background: rgba(0,0,0,0.5);
    display: flex;
    align-items: flex-end;
    justify-content: center;
    z-index: 1000;
    padding: 0;
}

.modal-content {
    background: var(--surface);
    border-radius: 20px 20px 0 0;
    padding: 24px;
    width: 100%;
    max-width: 768px;
    max-height: 80dvh;
    overflow-y: auto;
}

.modal-content h2 {
    margin-top: 0;
    margin-bottom: 20px;
}

.modal-actions {
    display: flex;
    gap: 12px;
    margin-top: 20px;
}

.modal-actions button {
    flex: 1;
}

/* Section header */
.section-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    margin-bottom: 16px;
}

.section-header h2 {
    margin: 0;
    font-size: 1.2rem;
}

/* Inspection detail */
.inspection-summary {
    background: var(--surface);
    border-radius: var(--radius);
    padding: 16px;
    margin-bottom: 20px;
    box-shadow: var(--shadow);
}

.summary-row {
    display: flex;
    justify-content: space-between;
    padding: 4px 0;
}

.summary-row span {
    color: var(--text-secondary);
}

/* Tabs */
.tab-bar {
    display: flex;
    background: var(--surface);
    border-radius: var(--radius);
    padding: 4px;
    margin-bottom: 16px;
    box-shadow: var(--shadow);
}

.tab {
    flex: 1;
    padding: 12px;
    border: none;
    background: none;
    font-size: 0.9rem;
    font-weight: 500;
    border-radius: 8px;
    cursor: pointer;
    color: var(--text-secondary);
    touch-action: manipulation;
}

.tab.active {
    background: var(--primary);
    color: white;
}

/* Checklist */
.checklist-category h3 {
    font-size: 1rem;
    color: var(--text-secondary);
    margin: 16px 0 8px;
    padding-bottom: 4px;
    border-bottom: 1px solid var(--border);
}

.checklist-item {
    background: var(--surface);
    border-radius: 8px;
    margin-bottom: 4px;
    overflow: hidden;
    border: 1px solid var(--border);
}

.checklist-item.item-pass { border-left: 4px solid var(--success); }
.checklist-item.item-fail { border-left: 4px solid var(--danger); }
.checklist-item.item-na { border-left: 4px solid #9e9e9e; }

.checklist-item-main {
    display: flex;
    align-items: center;
    gap: 12px;
    padding: 14px 12px;
    cursor: pointer;
    touch-action: manipulation;
    min-height: 52px;
}

.checklist-item-main:active {
    background: #f0f0f0;
}

.result-icon {
    font-size: 1.3rem;
    flex-shrink: 0;
}

.item-description {
    flex: 1;
    font-size: 0.95rem;
}

.btn-note-toggle {
    background: none;
    border: none;
    padding: 14px 12px;
    font-size: 1.1rem;
    cursor: pointer;
    touch-action: manipulation;
}

.item-notes {
    padding: 0 12px 12px;
}

.note-input {
    min-height: 60px;
    font-size: 0.9rem;
}

/* Photos */
.photos-section {
    display: flex;
    flex-direction: column;
    gap: 16px;
}

.photo-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(150px, 1fr));
    gap: 12px;
}

.photo-card {
    position: relative;
    border-radius: var(--radius);
    overflow: hidden;
    box-shadow: var(--shadow);
    background: var(--surface);
}

.photo-card img {
    width: 100%;
    aspect-ratio: 1;
    object-fit: cover;
    display: block;
}

.photo-caption-area {
    padding: 8px;
}

.caption-input {
    width: 100%;
    border: none;
    border-bottom: 1px solid var(--border);
    padding: 4px 0;
    font-size: 0.85rem;
    outline: none;
}

.caption-input:focus {
    border-color: var(--primary);
}

.btn-delete-photo {
    position: absolute;
    top: 4px;
    right: 4px;
    width: 28px;
    height: 28px;
    border-radius: 50%;
    background: rgba(0,0,0,0.6);
    color: white;
    border: none;
    cursor: pointer;
    font-size: 0.8rem;
    display: flex;
    align-items: center;
    justify-content: center;
}

/* Notes section */
.notes-section textarea {
    min-height: 200px;
}

/* Inspection actions */
.inspection-actions {
    margin-top: 20px;
    padding: 16px 0;
}

.status-select {
    font-weight: 500;
}

/* Connectivity bar */
.connectivity-bar {
    position: fixed;
    bottom: 0;
    left: 0;
    right: 0;
    padding: 8px 16px;
    text-align: center;
    font-size: 0.85rem;
    font-weight: 500;
    z-index: 1000;
    transition: all 0.3s;
}

.connectivity-bar.offline {
    background: #fef7e0;
    color: #e37400;
}

.connectivity-bar.online {
    background: transparent;
    pointer-events: none;
}

/* Sync badge */
.sync-badge {
    font-size: 0.8rem;
    padding: 4px 10px;
    border-radius: 12px;
    font-weight: 500;
}

.sync-badge.online { background: #e6f4ea; color: var(--success); }
.sync-badge.offline { background: #fef7e0; color: #e37400; }

